#!/usr/bin/env node
// postinstall: compile the yyork Go binary into dist/ when @yyopc/yyork is
// installed as a package. The published tarball ships the embedded dashboard
// (cmd/yyork/dashboard/app/**, built by `prepack`), so this only needs Go.
import { spawnSync } from 'node:child_process';
import { existsSync, mkdirSync, readFileSync } from 'node:fs';
import { dirname, resolve, sep } from 'node:path';
import { fileURLToPath } from 'node:url';

const rootDir = resolve(dirname(fileURLToPath(import.meta.url)), '..');

if (!isPackageInstall() && process.env.YYORK_FORCE_POSTINSTALL !== '1') {
  process.exit(0);
}

if (!hasCommand('go', ['version'])) {
  console.error(
    'yyork npm install requires Go 1.25+ on PATH to build the local yyork binary.'
  );
  process.exit(1);
}

const packageJSON = JSON.parse(readFileSync(resolve(rootDir, 'package.json')));
const distDir = resolve(rootDir, 'dist');
const binaryPath = resolve(
  distDir,
  process.platform === 'win32' ? 'yyork.exe' : 'yyork'
);

mkdirSync(distDir, { recursive: true });

const ldflags = [
  '-s',
  '-w',
  `-X github.com/yyopc/yyork/internal/cli.Version=${packageJSON.version}`,
].join(' ');

const result = spawnSync(
  'go',
  ['build', '-trimpath', '-ldflags', ldflags, '-o', binaryPath, '.'],
  {
    cwd: rootDir,
    shell: process.platform === 'win32',
    stdio: 'inherit',
  }
);

if (result.signal) {
  process.kill(process.pid, result.signal);
}
if (result.status !== 0 || !existsSync(binaryPath)) {
  process.exit(result.status ?? 1);
}

function isPackageInstall() {
  return rootDir.split(sep).includes('node_modules');
}

function hasCommand(command, args) {
  const result = spawnSync(command, args, { stdio: 'ignore' });
  return result.status === 0;
}
import { tanstackRouter } from '@tanstack/router-plugin/vite';
import viteReact from '@vitejs/plugin-react';
import { defineConfig, loadEnv } from 'vite';
import tsConfigPaths from 'vite-tsconfig-paths';

export default defineConfig(({ mode }) => {
  // Load env file based on `mode` in the current working directory.
  const env = loadEnv(mode, process.cwd(), 'VITE_');
  const backendOrigin = env.VITE_BACKEND_ORIGIN ?? 'http://127.0.0.1:7331';
  const webHost = env.VITE_HOST ?? '127.0.0.1';

  return {
    build: {
      // Build straight into the Go embed directory so there is no separate
      // copy step. `cmd/yyork/dashboard/.gitkeep` stays put (it satisfies
      // //go:embed on a fresh checkout); Vite only owns the `app/` subdir,
      // and emptyOutDir clears stale hashed assets each build. The embed and
      // dashboardFS() in the repo-root dashboard.go point at `dashboard/app`.
      outDir: '../cmd/yyork/dashboard/app',
      emptyOutDir: true,
    },
    server: {
      host: webHost,
      port: env.VITE_PORT ? Number(env.VITE_PORT) : 3000,
      proxy: {
        '/api': {
          changeOrigin: true,
          target: backendOrigin,
          ws: true,
        },
      },
      strictPort: true,
    },
    plugins: [
      tsConfigPaths(),
      // Generates src/route-tree.gen.ts from src/routes/. Replaces the
      // route-tree codegen that @tanstack/react-start used to do as part of
      // its SSR setup — we're now a client-only SPA.
      tanstackRouter({
        generatedRouteTree: './src/route-tree.gen.ts',
        target: 'react',
        autoCodeSplitting: true,
      }),
      // react's vite plugin must come after the router plugin.
      viteReact({
        babel: {
          plugins: ['babel-plugin-react-compiler'],
        },
      }),
    ],
  };
});
